SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
START TRANSACTION;
SET time_zone = "+00:00";

CREATE DATABASE IF NOT EXISTS `nexusdev` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;
USE `nexusdev`;



-- Users Table And Related Procedures --
CREATE TABLE IF NOT EXISTS `users`
(
  -- Keys --
  `uid` int(11) NOT NULL AUTO_INCREMENT,  -- Primary Key --
  
  -- Credentials --
  `email_address` varchar(320) NOT NULL,
  `password` text NOT NULL,

  -- Profile Info --
  `fname` varchar(32) NOT NULL,
  `mname` varchar(32) DEFAULT NULL,
  `lname` varchar(32) NOT NULL,
  `bio` varchar(1024) NOT NULL DEFAULT '',
  `pfp` varchar(255) DEFAULT NULL COMMENT 'Path to profile picture',

  -- Permissions --
  `freelancer` tinyint(1) NOT NULL DEFAULT 0,
  `owner_privileges` tinyint(1) NOT NULL DEFAULT 0,
  
  -- Constraints --
  Primary Key (uid)
)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




-- Orders Table, Related Tables And Procedures --
CREATE TABLE IF NOT EXISTS `orders`
(
  -- Keys --
  `oid` int(11) NOT NULL, -- Primary key --
  `uid` int(11) NOT NULL, -- Foreign key to users table --
  `freelancer_uid` int(11) NOT NULL DEFAULT -1, -- Foreign key to users table --

  -- Order Details --
  `title` varchar(32) NOT NULL,
  `description` varchar(1024) NOT NULL,
  `type` int(1) NOT NULL COMMENT '1: Website, 2: Desktop App, 3: Mobile App, 4: Other',
  `other_type` varchar(64) DEFAULT NULL, -- Only used if type is 4 (Other) --
  `platform` int(1) NOT NULL COMMENT '1: Windows, 2: Linux, 3: MacOS, 4: Android, 5: IOS', -- Only used for Desktop and Mobile App types --
  `budget` decimal(10,2) NOT NULL,
  `document_url` varchar(255) DEFAULT NULL COMMENT 'Path to the uploaded document',
  `deadline` date NOT NULL,

  -- Project datas --
  `project_version` varchar(32) NOT NULL DEFAULT '1.0.0.',
  `project_url` varchar(255) NULL DEFAULT NULL COMMENT 'Path to the downloadable project',

  -- Status --
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `status` int(1) NOT NULL DEFAULT '1' COMMENT '1: Pending, 2: In Progress, 3: Completed, 4: Cancelled',

  PRIMARY KEY (`oid`),
  FOREIGN KEY (`uid`) REFERENCES `users`(`uid`) ON DELETE CASCADE ON UPDATE CASCADE
)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




-- Order messages table --
CREATE TABLE IF NOT EXISTS `order_messages`
(
  -- Keys --
  `mid` int(11) NOT NULL AUTO_INCREMENT, -- Primary Key --
  `oid` int(11) NOT NULL, -- Foreign Key to orders table --
  `uid` int(11) NOT NULL, -- Foreign Key to users table --

  -- Message Details --
  `message` varchar(1024) NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,

  PRIMARY KEY (`mid`),
  FOREIGN KEY (`oid`) REFERENCES `orders`(`oid`) ON DELETE CASCADE ON UPDATE CASCADE,
  FOREIGN KEY (`uid`) REFERENCES `users`(`uid`) ON DELETE CASCADE ON UPDATE CASCADE
)
ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




COMMIT;